/**
 * Faithful generated diagnostic message catalog. DO NOT EDIT.
 *
 * Regenerate via `tools/generateDiagnostics.ts` (run `npm run diagnostics:generate`).
 *
 * 1:1 port of TS-Go `internal/diagnostics/diagnostics_generated.go` (2153 entries).
 * Upstream is itself generated by `internal/diagnostics/generate.go` from
 * TypeScript's `diagnosticMessages.json` and TS-Go's
 * `extraDiagnosticMessages.json`.
 *
 * Each upstream `var Name = &Message{...}` becomes one entry in the exported
 * `Diagnostics` table, keyed by the same exported identifier. The three
 * optional boolean flags (`reportsUnnecessary`, `elidedInCompatibilityPyramid`,
 * `reportsDeprecated`) are preserved exactly as upstream declares them.
 *
 * `keyToMessage` mirrors upstream's reverse-lookup switch: it maps a stable
 * `key` (`DiagnosticMessage.key`) back to its `DiagnosticMessage`, or
 * `undefined` when the key is unknown.
 */

import type { DiagnosticCategory } from "../enums/diagnosticCategory.enum.js";
import type { DiagnosticMessage as Message } from "./types.js";

const Category: {
  readonly Warning: DiagnosticCategory;
  readonly Error: DiagnosticCategory;
  readonly Suggestion: DiagnosticCategory;
  readonly Message: DiagnosticCategory;
} = {
  Warning: 0,
  Error: 1,
  Suggestion: 2,
  Message: 3,
};

interface MessageFlags {
  readonly reportsUnnecessary?: boolean;
  readonly reportsDeprecated?: boolean;
  readonly elidedInCompatibilityPyramid?: boolean;
}

function msg(code: number, category: DiagnosticCategory, key: string, text: string, flags?: MessageFlags): Message {
  const reportsUnnecessary = flags?.reportsUnnecessary === true;
  const reportsDeprecated = flags?.reportsDeprecated === true;
  const elidedInCompatibilityPyramid = flags?.elidedInCompatibilityPyramid === true;
  if (reportsUnnecessary && reportsDeprecated && elidedInCompatibilityPyramid) {
    return { code, category, key, message: text, reportsUnnecessary: true, reportsDeprecated: true, elidedInCompatibilityPyramid: true };
  }
  if (reportsUnnecessary && reportsDeprecated) {
    return { code, category, key, message: text, reportsUnnecessary: true, reportsDeprecated: true };
  }
  if (reportsUnnecessary && elidedInCompatibilityPyramid) {
    return { code, category, key, message: text, reportsUnnecessary: true, elidedInCompatibilityPyramid: true };
  }
  if (reportsDeprecated && elidedInCompatibilityPyramid) {
    return { code, category, key, message: text, reportsDeprecated: true, elidedInCompatibilityPyramid: true };
  }
  if (reportsUnnecessary) {
    return { code, category, key, message: text, reportsUnnecessary: true };
  }
  if (reportsDeprecated) {
    return { code, category, key, message: text, reportsDeprecated: true };
  }
  if (elidedInCompatibilityPyramid) {
    return { code, category, key, message: text, elidedInCompatibilityPyramid: true };
  }
  return {
    code,
    category,
    key,
    message: text,
  };
}

